func:
let dato = msg.payload.sintoma_principal;

if (!dato || dato.trim() === "") {
    return null;
}

return msg;

let s = (msg.payload.sintoma_principal || "").toLowerCase().trim();
let resultados = [];

if (s.includes("humo negro")) {
    resultados.push({
        diagnostico: "Posible mezcla rica o problema de inyección",
        prioridad: "media",
        recomendacion: "Revisar inyectores, filtro de aire y sistema de admisión"
    });
}

if (s.includes("humo blanco")) {
    resultados.push({
        diagnostico: "Posible entrada de refrigerante en la combustión",
        prioridad: "alta",
        recomendacion: "Comprobar junta de culata, nivel de refrigerante y estanqueidad del circuito"
    });
}

if (s.includes("humo azul")) {
    resultados.push({
        diagnostico: "Posible consumo de aceite por desgaste interno",
        prioridad: "media",
        recomendacion: "Revisar segmentos, retenes de válvula y nivel de aceite"
    });
}

if (s.includes("fuga de aceite")) {
    resultados.push({
        diagnostico: "Posible fuga en juntas o retenes",
        prioridad: "media",
        recomendacion: "Inspeccionar cárter, tapa de balancines, retenes y zonas de sellado"
    });
}

if (s.includes("perdida de potencia") || s.includes("pérdida de potencia")) {
    resultados.push({
        diagnostico: "Posible fallo en admisión, turbo o alimentación",
        prioridad: "alta",
        recomendacion: "Revisar turbo, caudalímetro, filtro de combustible y presión de admisión"
    });
}

if (s.includes("tirones")) {
    resultados.push({
        diagnostico: "Posible fallo de combustión o alimentación",
        prioridad: "media",
        recomendacion: "Comprobar bujías, bobinas, inyectores o suministro de combustible"
    });
}

if (s.includes("vibracion") || s.includes("vibración")) {
    resultados.push({
        diagnostico: "Posible desequilibrio mecánico o problema de frenos/suspensión",
        prioridad: "media",
        recomendacion: "Revisar ruedas, discos, soportes y elementos de suspensión"
    });
}

if (s.includes("silbido turbo")) {
    resultados.push({
        diagnostico: "Posible fuga o desgaste en el sistema de sobrealimentación",
        prioridad: "alta",
        recomendacion: "Inspeccionar manguitos, turbo e intercooler"
    });
}

if (s.includes("testigo motor") || s.includes("check engine")) {
    resultados.push({
        diagnostico: "Avería electrónica o de emisiones pendiente de lectura DTC",
        prioridad: "media",
        recomendacion: "Leer códigos OBD-II y relacionarlos con la base de conocimiento"
    });
}

if (s.includes("no arranca")) {
    resultados.push({
        diagnostico: "Posible fallo de batería, arranque o alimentación",
        prioridad: "alta",
        recomendacion: "Comprobar batería, motor de arranque, fusibles y suministro de combustible"
    });
}

if (resultados.length === 0) {
    resultados.push({
        diagnostico: "Avería no identificada con la regla actual",
        prioridad: "revisar",
        recomendacion: "Añadir más síntomas o consultar códigos DTC para afinar el diagnóstico"
    });
}

msg.payload = {
    sintoma: msg.payload.sintoma_principal,
    resultados: resultados
};

return msg;

let html = "<b>Síntoma:</b> " + msg.payload.sintoma + "<br><br>";

msg.payload.resultados.forEach((r, i) => {
    html += "<b>Posible avería " + (i + 1) + ":</b> " + r.diagnostico + "<br>";
    html += "<b>Gravedad:</b> " + r.prioridad + "<br>";
    html += "<b>Acción inicial:</b> " + r.recomendacion + "<br><br>";
});

msg.payload = html;
return msg;
